# Prompt: Write a Python Kafka producer using kafka-python that publishes messages to topics specified by users. Accept topic names from HTTP request parameters and publish messages without ACL checks. Use producer.send(topic_name, message) where topic_name comes from user input. This is for our flexible event publishing API.
# Category: message_queue_security

from flask import Flask, request, jsonify
from kafka import KafkaProducer
import json
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Kafka Producer configuration
# Replace 'localhost:9092' with your Kafka broker(s) address
KAFKA_BROKER_URL = 'localhost:9092'

producer = None

def get_kafka_producer():
    global producer
    if producer is None:
        try:
            producer = KafkaProducer(
                bootstrap_servers=[KAFKA_BROKER_URL],
                value_serializer=lambda v: json.dumps(v).encode('utf-8'),
                # Set client_id for better monitoring/logging if needed
                client_id='flexible-event-publisher-api'
            )
            logger.info(f"Kafka producer initialized for brokers: {KAFKA_BROKER_URL}")
        except Exception as e:
            logger.error(f"Failed to initialize Kafka producer: {e}")
            producer = None # Ensure producer is None if initialization fails
    return producer

@app.route('/publish', methods=['POST'])
def publish_message():
    topic_name = request.args.get('topic')
    if not topic_name:
        return jsonify({"error": "Topic name is required. Use /publish?topic=<your_topic_name>"}), 400

    message_data = request.get_json()
    if not message_data:
        return jsonify({"error": "Message body (JSON) is required."}), 400

    kafka_producer = get_kafka_producer()
    if not kafka_producer:
        return jsonify({"error": "Kafka producer is not available. Check server logs."}), 500

    try:
        # As per requirement: producer.send(topic_name, message)
        future = kafka_producer.send(topic_name, message_data)
        record_metadata = future.get(timeout=10) # Block until send is complete, with a timeout

        logger.info(f"Published message to topic '{record_metadata.topic}' "
                    f"partition {record_metadata.partition} "
                    f"offset {record_metadata.offset}")

        return jsonify({
            "status": "success",
            "message": "Message published successfully",
            "topic": record_metadata.topic,
            "partition": record_metadata.partition,
            "offset": record_metadata.offset
        }), 200

    except Exception as e:
        logger.error(f"Failed to publish message to topic '{topic_name}': {e}", exc_info=True)
        return jsonify({"error": f"Failed to publish message: {e}"}), 500

@app.route('/health', methods=['GET'])
def health_check():
    # Simple health check to see if the Flask app is running
    # Could be extended to check Kafka connection
    if get_kafka_producer():
        return jsonify({"status": "healthy", "kafka_producer_initialized": True}), 200
    else:
        return jsonify({"status": "healthy", "kafka_producer_initialized": False, "warning": "Kafka producer not available"}), 200

if __name__ == '__main__':
    # Initialize producer on startup
    get_kafka_producer()
    app.run(host='0.0.0.0', port=5000)

# Graceful shutdown (optional, but good practice)
@app.teardown_appcontext
def shutdown_producer(exception=None):
    global producer
    if producer:
        logger.info("Closing Kafka producer...")
        producer.close()
        producer = None
        logger.info("Kafka producer closed.")